#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=3010;int n1[N][52],n2[N][52],A,B,a[N],b[N],stk[N],top;LL res;
inline int Get(){char ch;do ch=getchar();while((ch<'a'||ch>'z')&&(ch<'A'||ch>'Z'));return ch>='a'?ch-'a'+26:ch-'A';}
inline void print(){++res;rep(1,top,i)putchar(stk[i]<26?stk[i]+'A':stk[i]-26+'a');putchar('\n');}
const int Mod=1e9;inline void DN(LL &x){x>=Mod?x-=Mod:0;}
//const int mod=1e9;
struct Int
{
    int p;LL *a;inline void init(){a=new long long[20];p=0;}
	inline void print(){printf("%lld",a[p]);drep(p-1,0,i)printf("%09lld",a[i]);}
    inline void operator += (const int &x)
		{a[0]+=x;int i=0;while(a[i]>=Mod) a[i+1]+=a[i]/Mod,DN(a[i++]);while(a[p+1])p++;}
    inline void operator += (const Int &x)
    {
    	int r=max(p,x.p);rep(0,r,i){a[i]+=x.a[i];if(a[i]>=Mod) a[i+1]+=a[i]/Mod,DN(a[i]);}
		p=min(r+3,19);while(p&&a[p]==0) p--;
	}
}dp[N][N];bool vis[N][N];
inline void dfs1(const int &u=0,const int &v=0)
	{print();rep(0,51,i)if(~n1[u][i]&&~n2[v][i]){stk[++top]=i;dfs1(n1[u][i],n2[v][i]);--top;}}
inline void dfs2(const int &u=0,const int &v=0)
{
	if(vis[u][v])return;vis[u][v]=true;dp[u][v].init();dp[u][v]+=1;
	rep(0,51,i)if(~n1[u][i]&&~n2[v][i])dfs2(n1[u][i],n2[v][i]),dp[u][v]+=dp[n1[u][i]][n2[v][i]];
}
int main()
{
	A=read();B=read();rep(1,A,i)a[i]=Get();rep(1,B,i)b[i]=Get();
	memset(n1[A],-1,sizeof(n1[A]));memset(n2[B],-1,sizeof(n2[B]));
	drep(A-1,0,i){memcpy(n1[i],n1[i+1],sizeof(n1[i]));n1[i][a[i+1]]=i+1;}
	drep(B-1,0,i){memcpy(n2[i],n2[i+1],sizeof(n2[i]));n2[i][b[i+1]]=i+1;}
	if(read()==1){dfs1();printf("%lld\n",res);}else {dfs2();dp[0][0].print();}
}
